    def _apply_process_priority(self, pid: int) -> None:
        """Best-effort attempt to apply ``self.process_priority`` to the
        given process id. Any failure, or an unsupported/unknown priority
        value, is silently ignored so the edit operation never fails
        because of this.
        """
        if self.process_priority is None:
            return

        if WIN:
            priority_class = _WIN_PRIORITY_CLASSES.get(self.process_priority)
            if priority_class is None:
                return
            try:
                import ctypes

                handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                    0x0200 | 0x0400, False, pid  # PROCESS_SET_INFORMATION | QUERY
                )
                if handle:
